CREATE TABLE IF NOT EXISTS `document_tags` (
  `id` int AUTO_INCREMENT PRIMARY KEY,
  `userId` int NOT NULL,
  `name` varchar(128) NOT NULL,
  `color` varchar(32) DEFAULT '#6366f1',
  `isAiGenerated` boolean DEFAULT false,
  `createdAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS `document_tag_map` (
  `id` int AUTO_INCREMENT PRIMARY KEY,
  `documentId` int NOT NULL,
  `tagId` int NOT NULL,
  `createdAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS `knowledge_gap_feedback` (
  `id` int AUTO_INCREMENT PRIMARY KEY,
  `userId` int NOT NULL,
  `gapId` varchar(128) NOT NULL,
  `gapTitle` varchar(512) NOT NULL,
  `gapCategory` varchar(128),
  `action` enum('dismiss','acknowledge','resolved','not_applicable') NOT NULL,
  `userNote` text,
  `createdAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE INDEX idx_doc_tags_user ON document_tags(userId);
CREATE INDEX idx_doc_tag_map_doc ON document_tag_map(documentId);
CREATE INDEX idx_doc_tag_map_tag ON document_tag_map(tagId);
CREATE INDEX idx_gap_feedback_user ON knowledge_gap_feedback(userId);
CREATE INDEX idx_gap_feedback_gap ON knowledge_gap_feedback(gapId);

